mapper.select:
SELECT id, user_id, product_id, quantity, selected, create_time, update_time
FROM cart
WHERE user_id = #{userId}
  AND product_id = #{productId}

mapper.update:
UPDATE cart

    quantity = #{quantity},
    selected = #{selected},

WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
DELETE
FROM cart
WHERE id = #{id}
  AND user_id = #{userId}
